#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
int nxt[maxn];
void get_nxt(string s) {
	int n=s.size();
	s=' '+s;
	nxt[1]=0;
	int len=0;
	for(int i=2; i<=n; i++) {
		while(len>0&&s[i]!=s[len+1]) {
			len=nxt[len];
		}
		if(s[i]==s[len+1]) {
			len++;
		}
		nxt[i]=len;
	}
}
string s,t;
int n;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>t;
	get_nxt(t);
	cout<<n-nxt[n];
	return 0;
}
